class EmployeeReceiptScreen extends StatefulWidget {
  const EmployeeReceiptScreen({super.key});
  @override
  State<EmployeeReceiptScreen> createState() => _EmployeeReceiptScreenState();
}

class _EmployeeReceiptScreenState extends State<EmployeeReceiptScreen> {
  final _searchCtrl = TextEditingController();
  List<_Receipt> _filtered = _kAllReceipts;

  @override
  void initState() {
    super.initState();
    _searchCtrl.addListener(() {
      final q = _searchCtrl.text.trim().toLowerCase();
      setState(() {
        _filtered = q.isEmpty
            ? _kAllReceipts
            : _kAllReceipts
                .where((r) =>
                    r.customer.toLowerCase().contains(q) ||
                    r.number.toLowerCase().contains(q))
                .toList();
      });
    });
  }

  @override
  void dispose() {
    _searchCtrl.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: AppColors.background,
