// ─── Summary strip ────────────────────────────────────────────────────────────

class _SummaryStrip extends StatelessWidget {
  const _SummaryStrip({required this.receipts});
  final List<_Receipt> receipts;

  @override
  Widget build(BuildContext context) {
    final total    = receipts.fold(0, (s, r) => s + r.totalAmount);
    final pending  = receipts.where((r) => r.status == _ReceiptStatus.pending).length;
    final complete = receipts.where((r) => r.status == _ReceiptStatus.complete).length;
    final fmt      = NumberFormat.currency(symbol: '₹', decimalDigits: 0);

    return Container(
      color: AppColors.surface2,
      padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 12),
      child: Row(
        children: [
          _StripStat(label: 'Total', value: fmt.format(total),  color: AppColors.primary),
          _StripDivider(),
          _StripStat(label: 'Pending',  value: '$pending',  color: AppColors.urgent),
          _StripDivider(),
          _StripStat(label: 'Complete', value: '$complete', color: AppColors.success),
        ],
      ),
    );
  }
}

class _StripStat extends StatelessWidget {
  const _StripStat(
      {required this.label, required this.value, required this.color});
  final String label, value;
  final Color  color;

  @override
  Widget build(BuildContext context) => Expanded(
        child: Column(
          children: [
            Text(value,
                style: TextStyle(
                    fontFamily: 'Poppins',
                    fontSize: 16,
                    fontWeight: FontWeight.w700,
                    color: color)),
            Text(label,
                style: const TextStyle(
                    fontFamily: 'Poppins',
                    fontSize: 11,
                    color: AppColors.textHint)),
          ],
        ),
      );
}

class _StripDivider extends StatelessWidget {
  @override
  Widget build(BuildContext context) => Container(
      width: 1, height: 30, color: AppColors.border,
      margin: const EdgeInsets.symmetric(horizontal: 8));
}

// ─── Receipt Card ─────────────────────────────────────────────────────────────

class _ReceiptCard extends StatelessWidget {
  const _ReceiptCard({required this.receipt});
  final _Receipt receipt;

  @override
  Widget build(BuildContext context) {
    late Color badgeColor;
    late String badgeText;
    switch (receipt.status) {
      case _ReceiptStatus.pending:
        badgeColor = AppColors.urgent;
        badgeText  = 'Pending';
        break;
      case _ReceiptStatus.complete:
        badgeColor = AppColors.success;
        badgeText  = 'Complete';
        break;
      case _ReceiptStatus.overdue:
        badgeColor = AppColors.error;
        badgeText  = 'Overdue';
        break;
    }

    final fmt = NumberFormat.currency(symbol: '₹', decimalDigits: 0);
    return Container(
      padding: const EdgeInsets.all(16),
      decoration: BoxDecoration(
        color: AppColors.surface,
        borderRadius: BorderRadius.circular(14),
        boxShadow: AppShadows.subtle,
        border: Border.all(color: AppColors.border),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            mainAxisAlignment: MainAxisAlignment.spaceBetween,
            children: [
              Text(receipt.number,
                  style: const TextStyle(
                      fontFamily: 'Poppins',
                      fontSize: 13,
                      fontWeight: FontWeight.w600,
                      color: AppColors.primary)),
              Container(
                padding:
                    const EdgeInsets.symmetric(horizontal: 10, vertical: 4),
                decoration: BoxDecoration(
                  color: badgeColor.withValues(alpha: 0.12),
                  borderRadius: BorderRadius.circular(8),
                  border: Border.all(color: badgeColor.withValues(alpha: 0.40)),
                ),
                child: Text(badgeText,
                    style: TextStyle(
                        fontFamily: 'Poppins',
                        fontSize: 11,
                        fontWeight: FontWeight.w600,
                        color: badgeColor)),
              ),
            ],
          ),
          const SizedBox(height: 10),
          Row(
            mainAxisAlignment: MainAxisAlignment.spaceBetween,
            crossAxisAlignment: CrossAxisAlignment.end,
            children: [
              Expanded(
                child: Text(receipt.customer,
                    style: const TextStyle(
                        fontFamily: 'Poppins',
                        fontSize: 15.5,
                        fontWeight: FontWeight.w700,
                        color: AppColors.textPrimary),
                    maxLines: 1,
                    overflow: TextOverflow.ellipsis),
              ),
              Text(fmt.format(receipt.totalAmount),
                  style: const TextStyle(
                      fontFamily: 'Poppins',
                      fontSize: 15.5,
                      fontWeight: FontWeight.w700,
                      color: AppColors.textPrimary)),
            ],
          ),
          const SizedBox(height: 10),
          const Divider(height: 1, color: AppColors.border),
          const SizedBox(height: 10),
          Row(
            children: [
              const Icon(Icons.calendar_today_rounded,
                  size: 13, color: AppColors.textHint),
              const SizedBox(width: 5),
              Text('Date: ${receipt.date}',
                  style: const TextStyle(
                      fontFamily: 'Poppins',
                      fontSize: 11.5,
                      color: AppColors.textSecondary)),
              const Spacer(),
              const Icon(Icons.local_shipping_rounded,
                  size: 13, color: AppColors.textHint),
